+
+func maxSnowflake(current, candidate string) string {
+	if current == "" {
+		return candidate
+	}
+	if candidate == "" {
+		return current
+	}
+	a, errA := strconv.ParseUint(current, 10, 64)
+	b, errB := strconv.ParseUint(candidate, 10, 64)
+	if errA != nil || errB != nil {
+		if candidate > current {
